mapper.select:


    r.del_flag = '0'
    AND r.type = #{type}
    AND r.inout_category_id = #{inoutCategoryId}
    AND r.warehouse_category_id = #{warehouseCategoryId}
    AND DATE(r.record_time) >= #{startDate}
    AND DATE(r.record_time) <= #{endDate}

ORDER BY r.record_time DESC, r.id DESC


WHERE r.del_flag = '0' AND (r.receiver_employee_id = #{employeeId} OR r.sender_employee_id = #{employeeId})
AND DATE(r.record_time) >= #{startDate}
AND DATE(r.record_time) <= #{endDate}
ORDER BY r.record_time DESC
LIMIT #{limit}
